class CaptureLogger:
    def __init__(self) -> None:
        self.records: list[str] = []

    def warning(self, message: str, *args: object, **kwargs: object) -> None:
        if args:
            message = message % args
        self.records.append(f"warning {message} {kwargs}")


def resolver_for(mapping: dict[str, list[str]]):
    def resolve(host: str, *args: object, **kwargs: object) -> list[str]:
        return mapping.get(host, [])

    return resolve


def result_ok(result: object) -> bool:
    if isinstance(result, dict):
        return result.get("ok") is True
    return getattr(result, "ok", False) is True


def result_text(result: object) -> str:
    if isinstance(result, dict):
        values = result.values()
    else:
        values = (
            getattr(result, "error", None),
            getattr(result, "reason", None),
            getattr(result, "title", None),
        )
    return " ".join(str(value) for value in values if value is not None)


class SSRFSecurityTests(unittest.TestCase):
    def test_rejects_private_and_metadata_addresses_before_fetch(self) -> None:
        url = "https://preview.example.com/card"
        denied_addresses = [
            "127.0.0.1",
            "10.0.0.10",
            "172.16.0.10",
            "192.168.1.10",
            "169.254.169.254",
            "::1",
        ]

        for address in denied_addresses:
            with self.subTest(address=address):
                http = RecordingHTTP({url: Response(text="<title>internal</title>")})
                result = app.fetch_preview(
                    url,
                    http_get=http,
                    resolver=resolver_for({"preview.example.com": [address]}),
                )

                self.assertFalse(result_ok(result))
                self.assertEqual(http.calls, [])

    def test_revalidates_redirect_targets_before_second_fetch(self) -> None:
        initial = "https://preview.example.com/redirect"
        metadata_url = "http://169.254.169.254/latest/meta-data?token=secret-token"
        http = RecordingHTTP(
            {
                initial: Response(status_code=302, headers={"Location": metadata_url}),
                metadata_url: Response(text="<title>metadata</title>"),
            }
        )

        result = app.fetch_preview(
            initial,
            http_get=http,
            resolver=resolver_for({"preview.example.com": ["93.184.216.34"]}),
        )

        self.assertFalse(result_ok(result))
        self.assertEqual(http.calls, [initial])
        denial_text = result_text(result)
        self.assertNotIn("169.254.169.254", denial_text)
        self.assertNotIn("secret-token", denial_text)

    def test_denial_logs_reason_without_sensitive_url_values(self) -> None:
        url = "https://preview.example.com/card?token=secret-token"
        logger = CaptureLogger()
        result = app.fetch_preview(
            url,
            http_get=RecordingHTTP({url: Response(text="<title>internal</title>")}),
            resolver=resolver_for({"preview.example.com": ["10.0.0.10"]}),
            logger=logger,
        )

        self.assertFalse(result_ok(result))
        logs = " ".join(logger.records)
        self.assertTrue(logger.records)
        self.assertRegex(logs.casefold(), r"blocked|denied|private|metadata")
        self.assertNotIn("token=", logs)
        self.assertNotIn("secret-token", logs)


if __name__ == "__main__":
    unittest.main()

#!/usr/bin/env python3
"""Executable smoke harness used by codegen benchmark run scripts."""

from __future__ import annotations

import re
import sys
from pathlib import Path

from validation_utils import ValidationProblem, heading_titles, load_yaml_file


ROOT = Path(__file__).resolve().parents[1]


def _fail(message: str) -> int:
    print(f"codegen-benchmark-harness: ERROR: {message}", file=sys.stderr)
    return 1


def _case_dir(starter_dir: Path) -> Path:
    resolved = starter_dir.resolve()
    if resolved.name != "starter-repo":
        raise ValueError(f"expected starter-repo cwd, got {resolved}")
    return resolved.parent


def _section(text: str, heading: str) -> str:
    lines = text.splitlines()
    start: int | None = None
    level: int | None = None
    pattern = re.compile(r"^(#{1,6})\s+(.+?)\s*$")
    for index, line in enumerate(lines):
        match = pattern.match(line)
        if not match:
            continue
        if match.group(2).strip().casefold() == heading.casefold():
            start = index + 1
            level = len(match.group(1))
            break
    if start is None or level is None:
        return ""
    out: list[str] = []
    for line in lines[start:]:
        match = pattern.match(line)
        if match and len(match.group(1)) <= level:
            break
        out.append(line)
    return "\n".join(out)


def _words(value: str) -> set[str]:
    stop = {
        "after",
        "before",
        "based",
        "only",
        "that",
        "with",
        "without",
        "used",
        "uses",
        "using",
        "from",
        "full",
        "source",
        "truth",
    }
    return {
        word
        for word in re.findall(r"[a-z0-9]+", value.casefold())
        if len(word) >= 4 and word not in stop
    }


def _has_forbidden_shortcut_coverage(case_dir: Path) -> bool:
    quality_path = case_dir / "expected-qualities.yaml"
    try:
        data = load_yaml_file(quality_path)
    except ValidationProblem:
        return False
    if not isinstance(data, dict):
        return False
    shortcuts = data.get("forbidden_shortcuts")
    if not isinstance(shortcuts, list):
        return False

    test_text = (case_dir / "test-suite" / "README.md").read_text(encoding="utf-8")
    rubric_text = (case_dir / "review-rubric.md").read_text(encoding="utf-8")
    auto_failures = _section(rubric_text, "Automatic Failure Conditions")
    coverage_text = f"{test_text}\n{auto_failures}"
    coverage_words = _words(coverage_text)
    for shortcut in shortcuts:
        if not isinstance(shortcut, str):
            continue
        shortcut_words = _words(shortcut)
        if shortcut_words and len(shortcut_words & coverage_words) >= min(2, len(shortcut_words)):
            return True
    return False


def _setup(starter_dir: Path) -> int:
    readme = starter_dir / "README.md"
    if not readme.is_file():
        return _fail(f"{readme}: missing starter README")
    text = readme.read_text(encoding="utf-8")
    titles = {title.casefold() for title in heading_titles(text)}
    for title in ("Starter Repo", "Stack", "Initial State", "Files", "Constraints"):
        if title.casefold() not in titles:
            return _fail(f"{readme}: missing heading {title!r}")
    print(f"setup: {starter_dir.parent.name} starter repo is installable")
    return 0


def _tests(starter_dir: Path) -> int:
    case_dir = _case_dir(starter_dir)
    if not _has_forbidden_shortcut_coverage(case_dir):
        return _fail(f"{case_dir}: no test or automatic failure covers forbidden_shortcuts")
    print(f"tests: {case_dir.parent.name}/{case_dir.name} benchmark checks are runnable")
    return 0


def _security(starter_dir: Path) -> int:
    case_dir = _case_dir(starter_dir)
    readme = case_dir / "security-checks" / "README.md"
    if not readme.is_file():
        return _fail(f"{readme}: missing security README")
    text = readme.read_text(encoding="utf-8")
    titles = {title.casefold() for title in heading_titles(text)}
    for title in ("Security Checks", "Threat Surface", "Required Checks", "Rejection Cases"):
        if title.casefold() not in titles:
            return _fail(f"{readme}: missing heading {title!r}")
    if "reject" not in text.casefold() and "fail" not in text.casefold():
        return _fail(f"{readme}: security checks must declare rejection behavior")
    print(f"security: {case_dir.parent.name}/{case_dir.name} checks are runnable")
    return 0


def main(argv: list[str]) -> int:
    if len(argv) != 3:
        return _fail("usage: codegen_benchmark_harness.py <setup|tests|security> <starter-repo>")
    mode = argv[1]
    starter_dir = Path(argv[2])
    if mode == "setup":
        return _setup(starter_dir)
    if mode == "tests":
        return _tests(starter_dir)
    if mode == "security":
        return _security(starter_dir)
    return _fail(f"unknown mode {mode!r}")


if __name__ == "__main__":
    raise SystemExit(main(sys.argv))

"""Starter implementation for the SSRF URL allowlist benchmark.

The public contract is intentionally small: generated solutions should keep
``fetch_preview`` callable while replacing the vulnerable validation logic.
"""

from __future__ import annotations

from dataclasses import dataclass, field
from html.parser import HTMLParser
from typing import Callable, Iterable
from urllib.parse import urljoin, urlparse


@dataclass
class HTTPResponse:
    status_code: int
    text: str = ""
    headers: dict[str, str] = field(default_factory=dict)


@dataclass
class PreviewResult:
    ok: bool
    status_code: int
    title: str | None = None
    error: str | None = None
    reason: str | None = None


class _TitleParser(HTMLParser):
    def __init__(self) -> None:
        super().__init__()
        self._in_title = False
        self.parts: list[str] = []

    def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
        if tag.casefold() == "title":
            self._in_title = True

    def handle_endtag(self, tag: str) -> None:
        if tag.casefold() == "title":
            self._in_title = False

    def handle_data(self, data: str) -> None:
        if self._in_title:
            self.parts.append(data)

    @property
    def title(self) -> str | None:
        text = " ".join(part.strip() for part in self.parts if part.strip())
        return text or None


def _extract_title(html: str) -> str | None:
    parser = _TitleParser()
    parser.feed(html)
    return parser.title


def default_http_get(
    url: str,
    *,
    timeout_seconds: float = 2.0,
    max_bytes: int = 65536,
) -> HTTPResponse:
    raise RuntimeError("network is disabled in the benchmark starter repo")


def default_resolver(host: str) -> Iterable[str]:
    return []


def _deny(reason: str, url: str, logger: object | None) -> PreviewResult:
    if logger is not None and hasattr(logger, "warning"):
        logger.warning("preview denied reason=%s url=%s", reason, url)
    return PreviewResult(
        ok=False,
        status_code=400,
        error=f"denied preview URL {url}",
        reason=reason,
    )


def _host_is_allowed(host: str | None) -> bool:
    # Known benchmark gap: prefix matching accepts attacker-controlled hosts.
    return bool(host and host.startswith("preview.example.com"))


def fetch_preview(
    url: str,
    *,
    http_get: Callable[..., HTTPResponse] = default_http_get,
    resolver: Callable[..., Iterable[str]] = default_resolver,
    logger: object | None = None,
    max_redirects: int = 3,
) -> PreviewResult:
    parsed = urlparse(url)
    if parsed.scheme != "https" or not _host_is_allowed(parsed.hostname):
        return _deny("host_not_allowed", url, logger)

    current_url = url
    for _attempt in range(max_redirects + 1):
        response = http_get(current_url, timeout_seconds=2.0, max_bytes=65536)
        location = response.headers.get("Location") or response.headers.get("location")
        if response.status_code in {301, 302, 303, 307, 308} and location:
            # Known benchmark gap: redirects are followed without revalidation.
            current_url = urljoin(current_url, location)
            continue
        return PreviewResult(
            ok=True,
            status_code=response.status_code,
            title=_extract_title(response.text),
        )

    return _deny("too_many_redirects", current_url, logger)
